// ========== クライアント情報をここに入力 ==========
const clientInfo = {
  shopName:     'hair salon ViHo',
  businessType: '美容室',
  location:     '高知市朝倉',
  features:     'マンツーマン・完全予約制・似合わせカット専門・プライベートサロン',
  phone:        '088-000-0000',
  address:      '高知県高知市朝倉○-○-○',
  services:     'カット 5,500円 / カラー 8,800円〜 / インナーカラー 11,000円〜 / ハイライト 16,500円〜',
  staffName:    '山田 花子',
  staffCareer:  '大阪の有名サロンで10年キャリアを積み、地元高知に戻り開業',
  instagram:    'https://www.instagram.com/example',
  line:         'https://lin.ee/example',
  mapEmbed:     ''
};
// =================================================

return [{ json: clientInfo }];

const c = $input.first().json;

const prompt = `あなたは高知県の小規模店舗向けWebサイトのコピーライターです。以下の店舗情報をもとに、Webサイトに掲載するコンテンツを生成してください。

店舗情報：
- 店舗名: ${c.shopName}
- 業種: ${c.businessType}
- 場所: ${c.location}
- 特徴: ${c.features}
- メニュー: ${c.services}
- スタッフ: ${c.staffName} / ${c.staffCareer}

ルール：
- AIっぽい表現禁止（シームレスな・革新的な・包括的な・洗練された等）
- 「〜をサポートします」「〜をお手伝いします」禁止
- 地域名・人名・具体的な数値を使う
- 体言止め・問いかけ・具体的な動詞を使う
- 保証・確約表現禁止

以下のJSON形式のみで出力してください（説明文は不要）：
{
  "tagline": "30文字以内のキャッチコピー",
  "subline": "エリアと特徴を含むサブキャッチ（30文字以内）",
  "seoTitle": "SEOタイトル（32文字以内）",
  "seoDescription": "meta description（120文字以内）",
  "staffBio": "スタッフ紹介文（150文字以内）",
  "services": [
    {"name": "メニュー名", "price": "料金", "desc": "40文字以内の説明"}
  ],
  "testimonials": [
    {"text": "お客様の声（60文字以内）", "name": "属性（例：30代女性）"}
  ]
}`;

const body = {
  model: 'claude-sonnet-4-6',
  max_tokens: 2000,
  messages: [{ role: 'user', content: prompt }]
};

return [{ json: { body, clientInfo: c } }];

const response = $input.first().json;
const text = response.content[0].text;

// JSONブロックを抽出
const jsonMatch = text.match(/```json\n?([\s\S]*?)\n?```/) || text.match(/(\{[\s\S]*\})/);
if (!jsonMatch) throw new Error('JSONが見つかりません: ' + text);

const jsonStr = jsonMatch[1] || jsonMatch[0];
const generated = JSON.parse(jsonStr);
const client = $('Claudeリクエストを準備').first().json.clientInfo;

return [{ json: { ...generated, client } }];
